import { NextRequest, NextResponse } from "next/server"
import { connectDB } from "@/lib/db"
import Template from "@/models/Template"
import Variable from "@/models/Variable"
import DealData from "@/models/DealData"
import Document from "@/models/Document"
import { buildFinalData } from "@/lib/buildFinalData"
import { generateDocx } from "@/lib/generateDocx"
import path from "path"
import fs from "fs"

export async function POST(req: NextRequest) {
  await connectDB()

  const { templateId, propertyId } = await req.json()

  const template = await Template.findById(templateId)
  const variables = await Variable.find({ templateId })
  const dealData = await DealData.findOne({ propertyId })

  const finalData = buildFinalData(variables, {
    deal: dealData?.data || {},
  })

  const templatePath = path.join(process.cwd(), "public", template.fileUrl)

  const count = await Document.countDocuments({ propertyId, templateId })
  const version = count + 1

  const outputPath = `/generated/${Date.now()}_v${version}.docx`
  const fullPath = path.join(process.cwd(), "public", outputPath)

  if (!fs.existsSync(path.dirname(fullPath))) {
    fs.mkdirSync(path.dirname(fullPath), { recursive: true })
  }

  generateDocx(templatePath, finalData, fullPath)

  await Document.create({
    propertyId,
    templateId,
    fileUrl: outputPath,
    version,
  })

  return NextResponse.json({ file: outputPath, version })
}